# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
from pymysql.cursors import DictCursor

def lambda_handler(event, context):
    # Connect to the database
    connection = pymysql.connect(host='YOUR_RDS_ENDPOINT', user='YOUR_USERNAME', password='YOUR_PASSWORD', db='YOUR_DB', cursorclass=DictCursor)
    
    with connection.cursor() as cursor:
        # Build the SQL query dynamically based on event parameters
        search_parameter = event['search_parameter'] if 'search_parameter' in event else None
        sorting_parameter = event['sorting_parameter'] if 'sorting_parameter' in event else None
        
        sql = "SELECT * FROM Products WHERE 1=1"
        
        if search_parameter:
            sql += f" AND (ProductName LIKE '%{search_parameter}%' OR ProductDescription LIKE '%{search_parameter}%')"
            
        if sorting_parameter and sorting_parameter.lower() in ['asc', 'desc']:
            sql += f" ORDER BY ProductPrice {sorting_parameter.upper()}"
        
        # Execute the SQL query
        cursor.execute(sql)
        
        # Fetch all results
        result = cursor.fetchall()
    
    connection.close()
    
    return {
        'statusCode': 200,
        'body': json.dumps({'products': result})
    }